const lead = $input.all()[0].json;

const confidence = lead.confidence || 0;
const emoji = confidence >= 80 ? '🔥' : confidence >= 60 ? '✅' : '📩';
const urgency = confidence >= 80 ? '*HIGH PRIORITY*' : confidence >= 60 ? 'Good lead' : 'New lead';

const lines = [
  `${emoji} ${urgency}: *${lead.customerName || 'Unknown'}*`,
  `📧 ${lead.customerEmail || 'No email'}`,
  lead.customerPhone ? `📞 ${lead.customerPhone}` : '',
  lead.fromAddress ? `📍 From: ${lead.fromAddress}` : '',
  lead.toAddress ? `🏠 To: ${lead.toAddress}` : '',
  lead.movingDate ? `📅 Date: ${lead.movingDate}` : '',
  (lead.services || []).length ? `🔧 Services: ${lead.services.join(', ')}` : '',
  `🎯 Confidence: ${confidence}%`,
  lead.rawEmailSubject ? `📨 Subject: _${lead.rawEmailSubject}_` : ''
].filter(Boolean);

const slackPayload = {
  text: lines.join('\n'),
  blocks: [
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: lines.join('\n')
      }
    },
    {
      type: 'divider'
    }
  ]
};

return [{ json: slackPayload }];
